<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
<title>YUMEKO VPN</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');

:root {
  --bg: #0d0f14;
  --bg2: #111318;
  --card: #1a1d24;
  --card2: #1e2128;
  --line: rgba(255,255,255,.07);
  --text: #e8eaf0;
  --muted: #6b7080;
  --cyan: #00d4ff;
  --blue: #4f7fff;
  --green: #2ecc71;
  --yellow: #f0c040;
  --red: #e74c3c;
  --orange: #e67e22;
  --nav-h: 68px;
}

* { box-sizing: border-box; -webkit-tap-highlight-color: transparent; margin: 0; padding: 0; }
html, body { min-height: 100%; background: var(--bg); }

body {
  font-family: Inter, system-ui, sans-serif;
  color: var(--text);
  overflow-x: hidden;
}

button { cursor: pointer; touch-action: manipulation; user-select: none; border: none; background: none; }

.app-shell {
  width: min(100%, 480px); margin: 0 auto;
  min-height: 100vh;
  display: flex; flex-direction: column;
  padding-bottom: calc(var(--nav-h) + env(safe-area-inset-bottom));
}

.page { display: none; flex-direction: column; flex: 1; }
.page.active { display: flex; }

/* HERO */
.hero-area {
  background: linear-gradient(180deg, #121620 0%, #0d0f14 100%);
  padding: 28px 20px 24px;
  display: flex; flex-direction: column; align-items: center;
  position: relative; overflow: hidden;
}
.hero-area::before {
  content: '';
  position: absolute; top: -60px; left: 50%; transform: translateX(-50%);
  width: 300px; height: 300px; border-radius: 50%;
  background: radial-gradient(circle, rgba(0,160,220,.18) 0%, transparent 70%);
  pointer-events: none;
}

.orb-wrap { position: relative; width: 180px; height: 180px; margin-bottom: 20px; }

.orb-ring-outer {
  position: absolute; inset: 0; border-radius: 50%;
  background: conic-gradient(from 0deg, #00bcd4, #7c4dff, #00bcd4);
  padding: 6px;
}
.orb-ring-outer::before {
  content: ''; position: absolute; inset: 6px; border-radius: 50%;
  background: #101520;
}
.orb-ring-inner {
  position: absolute; inset: 14px; border-radius: 50%;
  background: conic-gradient(from 180deg, #1a237e, #283593, #1a237e);
  padding: 3px;
}
.orb-ring-inner::before {
  content: ''; position: absolute; inset: 3px; border-radius: 50%;
  background: #101520;
}
.orb-btn {
  position: absolute; inset: 22px; border-radius: 50%;
  background: radial-gradient(circle at 38% 35%, #5c7cfa, #3d5af1 50%, #2a3ec7);
  display: grid; place-items: center;
  box-shadow: 0 0 30px rgba(60,100,255,.45), inset 0 2px 6px rgba(255,255,255,.15);
  transition: transform .12s, box-shadow .3s;
  border: none; cursor: pointer;
}
.orb-btn:active { transform: scale(.94); }

body.st-conectado .orb-btn {
  background: radial-gradient(circle at 38% 35%, #2ecc71, #27ae60 50%, #1e8449);
  box-shadow: 0 0 34px rgba(46,204,113,.45), inset 0 2px 6px rgba(255,255,255,.15);
}
body.st-conectando .orb-btn {
  background: radial-gradient(circle at 38% 35%, #f0c040, #d4a017 50%, #b8860b);
  box-shadow: 0 0 30px rgba(240,192,64,.4), inset 0 2px 6px rgba(255,255,255,.15);
}
body.st-erro .orb-btn {
  background: radial-gradient(circle at 38% 35%, #e74c3c, #c0392b 50%, #a93226);
  box-shadow: 0 0 30px rgba(231,76,60,.4), inset 0 2px 6px rgba(255,255,255,.15);
}

.orb-btn svg { width: 44px; height: 44px; color: #fff; filter: drop-shadow(0 2px 6px rgba(0,0,0,.4)); }

.orb-ring-outer::after {
  content: ''; position: absolute; inset: -3px; border-radius: 50%;
  border: 3px solid transparent;
  border-top-color: var(--cyan);
  opacity: 0; transition: opacity .3s;
}
body.st-conectando .orb-ring-outer::after { opacity: 1; animation: spin .8s linear infinite; }
@keyframes spin { to { transform: rotate(360deg); } }

.status-title {
  font-size: 22px; font-weight: 800; text-align: center;
  color: var(--text); transition: color .3s;
}
body.st-conectado .status-title { color: var(--green); }
body.st-conectando .status-title { color: var(--yellow); }
body.st-erro .status-title { color: var(--red); }

.status-sub { font-size: 13px; color: var(--muted); text-align: center; margin-top: 5px; font-weight: 500; }

.timer-bar {
  display: none; align-items: center; justify-content: center; gap: 8px;
  margin-top: 10px; padding: 6px 14px; border-radius: 20px;
  background: rgba(46,204,113,.1); border: 1px solid rgba(46,204,113,.25);
}
.timer-bar.show { display: flex; }
.timer-label { color: var(--green); font-weight: 800; font-size: 11px; letter-spacing: .06em; }
.timer-val { color: var(--green); font-weight: 900; font-size: 16px; font-variant-numeric: tabular-nums; }

.speed-row {
  display: grid; grid-template-columns: 1fr 1fr; gap: 10px;
  padding: 0 20px; margin-top: 18px;
}
.speed-card {
  background: var(--card); border-radius: 16px;
  padding: 12px 14px; border: 1px solid var(--line);
}
.speed-label { font-size: 10px; font-weight: 800; color: var(--muted); letter-spacing: .1em; text-transform: uppercase; }
.speed-val { font-size: 20px; font-weight: 900; margin-top: 4px; color: var(--text); font-variant-numeric: tabular-nums; }

.home-body { padding: 14px 14px 0; display: flex; flex-direction: column; gap: 10px; flex: 1; }

.checkuser-card {
  display: none; border-radius: 18px; padding: 14px 16px;
  background: var(--card); border: 1px solid rgba(0,212,255,.18);
}
.checkuser-card.show { display: block; }
.cu-title { font-size: 10px; font-weight: 900; letter-spacing: .1em; text-transform: uppercase; color: var(--cyan); margin-bottom: 10px; }
.cu-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
.cu-item-label { font-size: 10px; color: var(--muted); font-weight: 700; }
.cu-item-value { font-size: 13px; font-weight: 900; color: #fff; margin-top: 2px; }
.cu-item-value.green { color: var(--green); }

.time-card {
  display: none; border-radius: 18px; padding: 14px 16px;
  background: var(--card); border: 1px solid rgba(240,192,64,.25);
}
.time-card.show { display: block; }
.time-card-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 10px; }
.time-card-title { font-size: 10px; font-weight: 900; letter-spacing: .1em; text-transform: uppercase; color: var(--yellow); }
.time-remaining { font-size: 20px; font-weight: 900; font-variant-numeric: tabular-nums; color: var(--yellow); }
.time-bar-track { height: 4px; background: rgba(255,255,255,.07); border-radius: 999px; overflow: hidden; margin-bottom: 12px; }
.time-bar-fill { height: 100%; background: linear-gradient(90deg, var(--yellow), var(--orange)); border-radius: 999px; transition: width .5s; }
.watch-ad-btn {
  width: 100%; padding: 12px; border-radius: 14px;
  background: rgba(240,192,64,.12); border: 1px solid rgba(240,192,64,.3);
  color: var(--yellow); font-size: 13px; font-weight: 900; cursor: pointer; transition: opacity .15s;
}
.watch-ad-btn:active { opacity: .75; }
.watch-ad-btn:disabled { opacity: .35; cursor: not-allowed; }

.message-card {
  display: none; align-items: center; gap: 12px;
  padding: 13px 15px; border-radius: 16px;
  background: var(--card); border: 1px solid rgba(240,192,64,.25);
}
.message-card.show { display: flex; }
.msg-icon { font-size: 18px; }
.msg-title { font-size: 10px; font-weight: 900; letter-spacing: .1em; text-transform: uppercase; color: var(--yellow); }
.msg-text { font-size: 12px; color: rgba(255,255,255,.85); margin-top: 2px; }

.server-card {
  background: var(--card); border-radius: 18px;
  padding: 14px 16px; border: 1px solid var(--line);
  display: flex; align-items: center; gap: 13px;
  cursor: pointer; transition: opacity .15s;
}
.server-card:active { opacity: .75; }
.sc-icon {
  width: 44px; height: 44px; border-radius: 14px;
  background: rgba(79,127,255,.12); display: grid; place-items: center;
  font-size: 20px; flex: 0 0 44px; overflow: hidden;
}
.sc-icon img { width: 100%; height: 100%; object-fit: cover; border-radius: 10px; }
.sc-meta { flex: 1; min-width: 0; }
.sc-label { font-size: 10px; font-weight: 900; color: var(--cyan); letter-spacing: .1em; text-transform: uppercase; }
.sc-title { font-size: 15px; font-weight: 800; margin-top: 3px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sc-sub { font-size: 11px; color: var(--muted); margin-top: 2px; font-weight: 600; }
.sc-chev { color: var(--muted); font-size: 18px; flex: 0 0 auto; }

.creds-block {
  background: var(--card); border-radius: 18px;
  padding: 10px 12px; border: 1px solid var(--line);
  display: flex; flex-direction: column; gap: 8px;
  cursor: pointer;
}
.creds-field {
  display: flex; align-items: center; gap: 10px;
  background: var(--card2); border-radius: 12px;
  padding: 11px 14px; border: 1px solid var(--line);
  pointer-events: none;
}
.creds-field-icon { font-size: 16px; flex: 0 0 auto; }
.creds-field input {
  flex: 1; background: none; border: none; outline: none;
  color: var(--muted); font-size: 14px; font-weight: 600;
  font-family: inherit;
}
.creds-field input::placeholder { color: var(--muted); }

.action-row {
  display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px;
  padding: 0 0 4px;
}
.action-pill {
  background: var(--card2); border: 1px solid var(--line);
  border-radius: 14px; padding: 14px 6px;
  display: flex; flex-direction: column; align-items: center; gap: 6px;
  color: var(--muted); font-size: 10px; font-weight: 800;
  text-transform: uppercase; letter-spacing: .05em; cursor: pointer;
  transition: opacity .15s;
}
.action-pill:active { opacity: .7; }
.action-pill .ap-icon { font-size: 20px; color: var(--text); }

.version-row { text-align: center; color: var(--muted); font-size: 11px; font-weight: 700; padding: 6px 0 2px; }

.page-header {
  padding: 18px 18px 12px;
  display: flex; align-items: center; gap: 12px;
}
.page-title { font-size: 18px; font-weight: 900; }

.server-list-wrap { padding: 0 14px; flex: 1; overflow-y: auto; }

.list-item {
  display: flex; align-items: center; gap: 12px;
  padding: 13px 14px; border-radius: 18px; margin-bottom: 9px;
  background: var(--card); border: 1px solid var(--line);
  cursor: pointer; transition: opacity .15s;
}
.list-item:active { opacity: .75; }
.list-item.selected { border-color: rgba(0,212,255,.45); background: rgba(0,212,255,.07); }
.li-icon {
  width: 42px; height: 42px; flex: 0 0 42px; border-radius: 13px;
  display: grid; place-items: center;
  background: rgba(79,127,255,.1); color: var(--cyan); overflow: hidden; font-size: 18px;
}
.li-icon img { width: 100%; height: 100%; object-fit: cover; }
.li-main { min-width: 0; flex: 1; }
.li-title { font-weight: 800; font-size: 14px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.li-sub { color: var(--muted); font-size: 11px; margin-top: 4px; font-weight: 600; }
.li-check { color: var(--cyan); display: none; font-size: 18px; }
.list-item.selected .li-check { display: block; }

.speed-page-body { padding: 10px 18px; flex: 1; display: flex; flex-direction: column; gap: 14px; }
.speed-big-card {
  background: var(--card); border-radius: 22px; padding: 22px;
  border: 1px solid var(--line); text-align: center;
}
.speed-big-label { font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: .12em; color: var(--muted); }
.speed-big-val { font-size: 48px; font-weight: 900; font-variant-numeric: tabular-nums; margin: 8px 0 4px; }
.speed-big-unit { font-size: 13px; color: var(--muted); font-weight: 700; }
.speed-dl { color: var(--cyan); }
.speed-ul { color: var(--green); }
.speed-cards-row { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }

.tools-body { padding: 10px 14px; flex: 1; display: flex; flex-direction: column; gap: 10px; }
.tool-btn {
  background: var(--card); border: 1px solid var(--line);
  border-radius: 18px; padding: 16px 18px;
  display: flex; align-items: center; gap: 14px;
  cursor: pointer; transition: opacity .15s; width: 100%;
}
.tool-btn:active { opacity: .75; }
.tool-btn-icon { font-size: 24px; width: 44px; height: 44px; display: grid; place-items: center; background: rgba(255,255,255,.05); border-radius: 14px; flex: 0 0 44px; }
.tool-btn-text { text-align: left; }
.tool-btn-title { font-size: 15px; font-weight: 800; }
.tool-btn-sub { font-size: 12px; color: var(--muted); margin-top: 3px; font-weight: 600; }
.tool-btn-chev { margin-left: auto; color: var(--muted); font-size: 18px; }

.logs-toolbar {
  display: flex; gap: 8px; justify-content: flex-end;
  padding-bottom: 10px; border-bottom: 1px solid rgba(255,255,255,.06);
  margin-bottom: 10px;
}
.log-action-btn {
  padding: 6px 12px; border-radius: 10px; font-size: 11px; font-weight: 900;
  background: rgba(255,255,255,.07); border: 1px solid rgba(255,255,255,.1); color: var(--text);
}
.log-action-btn:active { opacity: .7; }
.log-action-btn.danger { background: rgba(231,76,60,.12); border-color: rgba(231,76,60,.3); color: var(--red); }

#log-container { font-family: 'Courier New', monospace; font-size: 11.5px; line-height: 1.65; }
.log-entry {
  display: flex; gap: 8px; align-items: flex-start;
  padding: 5px 8px; border-radius: 10px; margin-bottom: 3px;
  border-left: 2.5px solid transparent;
}
.log-entry.INFO { background: rgba(255,255,255,.03); border-left-color: rgba(137,155,255,.4); }
.log-entry.DEBUG { background: rgba(0,212,255,.04); border-left-color: rgba(0,212,255,.3); }
.log-entry.WARNING { background: rgba(240,192,64,.06); border-left-color: var(--yellow); }
.log-entry.ERROR { background: rgba(231,76,60,.07); border-left-color: var(--red); }
.log-time { color: var(--muted); font-size: 10px; white-space: nowrap; padding-top: 1px; flex: 0 0 auto; }
.log-msg { color: var(--text); word-break: break-all; }
.log-entry.WARNING .log-msg { color: var(--yellow); }
.log-entry.ERROR .log-msg { color: var(--red); }
.log-entry.DEBUG .log-msg { color: rgba(0,212,255,.85); }

.bottom-nav {
  position: fixed; bottom: 0; left: 50%; transform: translateX(-50%);
  width: min(100%, 480px);
  height: calc(var(--nav-h) + env(safe-area-inset-bottom));
  padding-bottom: env(safe-area-inset-bottom);
  background: #14161e;
  border-top: 1px solid rgba(255,255,255,.06);
  display: grid; grid-template-columns: repeat(4, 1fr);
  z-index: 50;
}
.nav-btn {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  gap: 5px; color: var(--muted); font-size: 9px; font-weight: 800;
  text-transform: uppercase; letter-spacing: .06em;
  transition: color .2s; position: relative; padding: 0;
}
.nav-btn.active { color: var(--text); }
.nav-btn.active::before {
  content: ''; position: absolute; top: 0; left: 20%; right: 20%; height: 2px;
  background: var(--cyan); border-radius: 0 0 4px 4px;
}
.nav-btn svg { width: 22px; height: 22px; }

.modal-mask {
  position: fixed; inset: 0; z-index: 80;
  display: flex; align-items: flex-end; justify-content: center;
  padding: 14px; background: rgba(0,0,0,.6);
  opacity: 0; pointer-events: none; transition: .22s;
}
.modal-mask.show { opacity: 1; pointer-events: auto; }
.modal-box {
  display: none; flex-direction: column;
  width: min(100%, 460px); max-height: 80vh;
  border-radius: 24px 24px 18px 18px;
  background: #13161f; border: 1px solid rgba(255,255,255,.08);
  overflow: hidden;
  transform: translateY(24px); opacity: 0;
  transition: transform .22s, opacity .22s;
}
.modal-mask.show .modal-box.active { display: flex; transform: translateY(0); opacity: 1; }
.modal-head {
  display: flex; align-items: center; justify-content: space-between;
  padding: 16px 16px 12px; border-bottom: 1px solid rgba(255,255,255,.07);
  flex: 0 0 auto;
}
.modal-title { font-weight: 900; font-size: 16px; }
.icon-btn {
  width: 40px; height: 40px; border-radius: 12px;
  display: inline-flex; align-items: center; justify-content: center;
  color: var(--text); background: rgba(255,255,255,.07);
  font-size: 20px; cursor: pointer;
}
.icon-btn:active { opacity: .75; }
.modal-body { padding: 14px; overflow-y: auto; flex: 1; }

.toast-box { position: fixed; z-index: 120; left: 14px; right: 14px; bottom: calc(var(--nav-h) + 10px + env(safe-area-inset-bottom)); display: grid; place-items: center; pointer-events: none; }
.toast {
  padding: 11px 15px; border-radius: 14px;
  background: rgba(13,15,20,.96); color: var(--text);
  border: 1px solid rgba(0,212,255,.2);
  font-size: 13px; font-weight: 800;
  opacity: 0; transform: translateY(8px); transition: .2s ease;
  max-width: min(92vw, 400px); text-align: center;
}
.toast.show { opacity: 1; transform: translateY(0); }
.toast.ok { border-color: rgba(46,204,113,.4); }
.toast.err { border-color: rgba(231,76,60,.45); }
.toast.warn { border-color: rgba(240,192,64,.4); }

.method-modal-box {
  background: #151c22;
  border-radius: 24px 24px 20px 20px;
  border: 1px solid rgba(46,204,113,.18);
  overflow: hidden;
}
.method-modal-head { display: flex; align-items: center; justify-content: space-between; padding: 20px 20px 14px; }
.method-modal-title { font-size: 20px; font-weight: 900; color: var(--text); }
.method-close-btn { color: var(--green); font-size: 14px; font-weight: 800; background: none; border: none; cursor: pointer; padding: 4px 8px; }
.method-modal-sub { color: var(--muted); font-size: 13px; padding: 0 20px 16px; }
.method-list { padding: 0 12px 16px; display: flex; flex-direction: column; gap: 10px; }
.method-item {
  border-radius: 16px; padding: 16px 18px;
  background: rgba(255,255,255,.05); border: 1px solid rgba(255,255,255,.08);
  cursor: pointer; transition: opacity .15s;
  display: flex; align-items: center; justify-content: space-between;
}
.method-item:active { opacity: .75; }
.method-item.active-method { background: linear-gradient(135deg, #2ecc71, #27ae60); border-color: transparent; }
.method-item.active-method .mi-title,
.method-item.active-method .mi-sub { color: #fff; }
.method-item.active-method .mi-badge { display: block; }
.mi-title { font-size: 15px; font-weight: 900; color: var(--text); }
.mi-sub { font-size: 12px; color: var(--muted); margin-top: 3px; font-weight: 600; }
.mi-badge { display: none; font-size: 12px; font-weight: 900; color: #fff; background: rgba(0,0,0,.25); padding: 4px 10px; border-radius: 20px; }

.creds-modal-box {
  background: #13161f;
  border-radius: 24px 24px 20px 20px;
  border: 1px solid rgba(255,255,255,.08);
  overflow: hidden;
}
.creds-modal-head {
  display: flex; align-items: center; justify-content: space-between;
  padding: 18px 18px 10px;
  border-bottom: 1px solid rgba(255,255,255,.06);
}
.creds-modal-title { font-size: 17px; font-weight: 900; }
.creds-modal-sub { font-size: 12px; color: var(--muted); padding: 10px 18px 4px; }
.creds-modal-body { padding: 10px 18px 18px; overflow-y: auto; flex: 1; }
.creds-section-title {
  font-size: 12px; font-weight: 900; color: var(--cyan);
  text-transform: uppercase; letter-spacing: .1em;
  margin: 14px 0 8px;
}
.creds-input-wrap {
  background: var(--card2); border-radius: 13px;
  border: 1px solid var(--line);
  display: flex; align-items: center; gap: 10px;
  padding: 12px 14px; margin-bottom: 8px;
}
.creds-input-wrap input {
  flex: 1; background: none; border: none; outline: none;
  color: var(--text); font-size: 14px; font-weight: 600; font-family: inherit;
}
.creds-input-wrap input::placeholder { color: var(--muted); }
.ci-icon { color: var(--muted); font-size: 16px; flex: 0 0 auto; }
.ci-eye { color: var(--muted); font-size: 16px; flex: 0 0 auto; background: none; border: none; cursor: pointer; }
.creds-modal-footer { display: flex; gap: 10px; padding: 0 18px 18px; }
.creds-cancel-btn {
  flex: 1; padding: 14px; border-radius: 14px;
  background: rgba(255,255,255,.07); border: 1px solid rgba(255,255,255,.1);
  color: var(--text); font-size: 14px; font-weight: 800; cursor: pointer; transition: opacity .15s;
}
.creds-save-btn {
  flex: 1; padding: 14px; border-radius: 14px;
  background: linear-gradient(135deg, #2ecc71, #27ae60);
  border: none; color: #fff; font-size: 14px; font-weight: 900; cursor: pointer; transition: opacity .15s;
}
.creds-cancel-btn:active, .creds-save-btn:active { opacity: .75; }

.method-pill-btn {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 6px 12px; border-radius: 20px;
  background: rgba(46,204,113,.12); border: 1px solid rgba(46,204,113,.3);
  color: var(--green); font-size: 11px; font-weight: 900;
  text-transform: uppercase; letter-spacing: .08em;
  cursor: pointer; transition: opacity .15s; margin-top: 8px;
}
.method-pill-btn:active { opacity: .75; }

@media (max-width: 370px) {
  .orb-wrap { width: 150px; height: 150px; }
  .status-title { font-size: 18px; }
}
</style>
</head>
<body>
<div class="app-shell">

  <!-- HOME -->
