<script>
(function () {
'use strict';

var A = {
  call: function (m, arg) {
    try {
      if (window.Android && typeof window.Android[m] === 'function')
        return arg !== undefined ? window.Android[m](arg) : window.Android[m]();
    } catch (e) { console.warn('Bridge.' + m, e); }
    return null;
  },
  parse: function (raw, fb) {
    try { return JSON.parse(raw) || fb; } catch (e) { return fb; }
  },
  connect:            function ()    { A.call('connect'); },
  getStatus:          function ()    { return A.call('getStatus') || 'DESCONECTADO'; },
  getServers:         function ()    { return A.parse(A.call('getServers'), []); },
  getSelected:        function ()    { return A.parse(A.call('getSelectedServer'), {}); },
  selectServer:       function (pos) { A.call('selectServer', pos); },
  getMultiServers:    function ()    { return A.parse(A.call('getMultiServers'), []); },
  getSelectedMulti:   function ()    { return A.parse(A.call('getSelectedMultiServer'), {}); },
  selectMultiServer:  function (pos) { A.call('selectMultiServer', pos); },
  getNote:            function ()    { return A.call('getNote') || ''; },
  getVersion:         function ()    { return A.call('getVersion') || ''; },
  getLogs:            function ()    { return A.parse(A.call('getLogs'), []); },
  clearLogs:          function ()    { A.call('clearLogs'); },
  openServers:        function ()    { A.call('openServers'); },
  checkUpdate:        function ()    { A.call('checkUpdate'); },
  requestInterstitial:function ()    { A.call('requestInterstitial'); },
  isAdsEnabled:       function ()    { return window.Android && typeof Android.isAdsEnabled === 'function' ? Android.isAdsEnabled() : false; },
  getTimeLeft:        function ()    { return window.Android && typeof Android.getTimeLeft === 'function' ? Android.getTimeLeft() : 0; },
  watchAd:            function ()    { A.call('watchAd'); }
};

var STATE = {
  CONECTADO:    { cls: 'st-conectado',   label: 'Protegido',         sub: 'Sua conexão está segura.',                              auth: 'ONLINE', authOk: true,  btn: 'DESCONECTAR' },
  DESCONECTADO: { cls: 'st-desconectado',label: 'Proteção pausada',  sub: 'Toque no botão central para iniciar uma sessão segura.',auth: '—',      authOk: false, btn: 'CONECTAR' },
  INICIANDO:    { cls: 'st-conectando',  label: 'Iniciando...',      sub: 'Preparando conexão...',                                 auth: '...',    authOk: false, btn: 'CANCELAR' },
  PARANDO:      { cls: 'st-conectando',  label: 'Parando...',        sub: 'Encerrando túnel...',                                   auth: '...',    authOk: false, btn: 'AGUARDE...' },
  CONECTANDO:   { cls: 'st-conectando',  label: 'Conectando...',     sub: 'Estabelecendo conexão segura...',                       auth: '...',    authOk: false, btn: 'CANCELAR' },
  AGUARDANDO:   { cls: 'st-conectando',  label: 'Aguardando...',     sub: 'Aguardando resposta do servidor...',                    auth: '...',    authOk: false, btn: 'CANCELAR' },
  AUTENTICANDO: { cls: 'st-conectando',  label: 'Autenticando...',   sub: 'Verificando credenciais...',                            auth: '...',    authOk: false, btn: 'CANCELAR' },
  RECONECTANDO: { cls: 'st-conectando',  label: 'Reconectando...',   sub: 'Tentando restaurar conexão...',                         auth: '...',    authOk: false, btn: 'CANCELAR' },
  NOPROCESS:    { cls: '',               label: 'Proteção pausada',  sub: 'Toque no botão central para iniciar uma sessão segura.',auth: '—',      authOk: false, btn: 'CONECTAR' },
  ERRO:         { cls: 'st-erro',        label: 'Falha na conexão',  sub: 'Verifique suas configurações e tente novamente.',       auth: 'FALHA',  authOk: false, btn: 'TENTAR NOVAMENTE' }
};

var ALL_STATE_CLASSES = ['st-conectado', 'st-conectando', 'st-desconectado', 'st-erro'];
var app = { rawState: 'NOPROCESS', connected: false, busy: false, startedAt: 0, timerHandle: null, pollHandle: null, _mode: 'SSH' };

function $(id) { return document.getElementById(id); }
function setText(id, v) { var el = $(id); if (el) el.textContent = String(v == null ? '' : v); }
function pad(n) { return String(n).padStart(2, '0'); }
function esc(s) { return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

function toast(msg, kind) {
  var el = $('toast'); if (!el) return;
  el.textContent = msg;
  el.className = 'toast show' + (kind ? ' ' + kind : '');
  clearTimeout(el._t);
  el._t = setTimeout(function () { el.className = 'toast'; }, 2800);
}

function showPage(name) {
  document.querySelectorAll('.page').forEach(function (p) { p.classList.remove('active'); });
  document.querySelectorAll('.nav-btn').forEach(function (b) { b.classList.remove('active'); });
  var pg = $('page-' + name); if (pg) pg.classList.add('active');
  var nb = $('nav-' + name); if (nb) nb.classList.add('active');
  if (name === 'servers') buildServerListPage();
}

function applyState(raw, detail) {
  raw = String(raw || 'NOPROCESS').toUpperCase().trim();
  app.rawState = raw;
  var s = STATE[raw] || STATE['NOPROCESS'];

  ALL_STATE_CLASSES.forEach(function (c) { document.body.classList.remove(c); });
  if (s.cls) document.body.classList.add(s.cls);

  setText('status-label', s.label);
  setText('status-detail', detail || s.sub);
  setText('speed-status-label', s.label);

  var modePill = $('speed-mode-pill');
  if (modePill) modePill.textContent = (s.auth === 'ONLINE' ? '✓ ' : '') + app._mode;

  app.connected = (raw === 'CONECTADO');
  app.busy = ['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO','PARANDO'].indexOf(raw) >= 0;

  if (app.connected && !app.startedAt) { app.startedAt = Date.now(); startTimer(); }
  if (!app.connected && !app.busy) {
    if (app.startedAt) { app.startedAt = 0; stopTimer(); setText('timer-val','00:00'); }
    var tb = $('timer-bar'); if (tb) tb.classList.remove('show');
  }
}

function startTimer() {
  stopTimer();
  var tb = $('timer-bar'); if (tb) tb.classList.add('show');
  app.timerHandle = setInterval(function () {
    var sec = Math.floor((Date.now() - app.startedAt) / 1000);
    var h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
    setText('timer-val', (h ? pad(h) + ':' : '') + pad(m) + ':' + pad(s));
  }, 1000);
}
function stopTimer() { if (app.timerHandle) { clearInterval(app.timerHandle); app.timerHandle = null; } }

function startPolling() {
  app.pollHandle = setInterval(function () {
    var raw = A.getStatus();
    if (raw !== app.rawState) applyState(raw);
  }, 1200);
}

function renderLogs() {
  var container = $('log-container'); if (!container) return;
  var logs = A.getLogs();
  if (!logs || !logs.length) { container.innerHTML = '<div style="color:var(--muted);font-size:12px;padding:8px">Nenhum log disponível.</div>'; return; }
  var html = '';
  for (var i = logs.length - 1; i >= 0; i--) {
    var item = logs[i];
    var level = String(item.level || 'INFO').toUpperCase();
    var msg = esc(item.message || '');
    var time = item.time ? formatLogTime(item.time) : '';
    html += '<div class="log-entry ' + level + '"><span class="log-time">' + esc(time) + '</span><span class="log-msg">' + msg + '</span></div>';
  }
  container.innerHTML = html;
}

function formatLogTime(ms) {
  var d = new Date(ms); return pad(d.getHours()) + ':' + pad(d.getMinutes()) + ':' + pad(d.getSeconds());
}

function loadSavedCredentials() {
  try {
    var raw = window.Android && window.Android.getSavedCredentials ? window.Android.getSavedCredentials() : '{}';
    var creds = JSON.parse(raw);
    var fUser = $('ci-ssh-user'), fPass = $('ci-ssh-pass');
    var fUdp = $('ci-udp-token'), fV2 = $('ci-v2ray-uuid');
    if (fUser) fUser.value = creds.sshUser || '';
    if (fPass) fPass.value = creds.sshPass || '';
    if (fUdp)  fUdp.value  = creds.udpToken || '';
    if (fV2)   fV2.value   = creds.v2uuid || '';
  } catch (e) { console.warn('Erro ao carregar credenciais', e); }
}

function refreshInfo() {
  var ver = A.getVersion(); if (ver) setText('config-version', ver);
  var note = A.getNote();
  var mc = $('message-card'); if (mc) { mc.classList.toggle('show', !!note); setText('message-text', note); }
}

function refreshSelected() {
  var s = A.getSelected();
  if (s && s.Name) {
    setText('server-title', s.Name || 'Servidor automático');
    setText('server-sub', s.Info || 'Funcionando');
    app._mode = s.Info || 'SSH';
    setText('speed-mode-pill', s.Info || 'SSH');
    var wrap = $('server-flag-wrap');
    if (wrap && (s.FlagUrl || s.Flag)) {
      var src = s.FlagUrl ? s.FlagUrl : 'file:///android_asset/flags/' + s.Flag + '.png';
      wrap.innerHTML = '<img src="' + esc(src) + '" onerror="this.parentElement.innerHTML=\'🌐\'" style="width:100%;height:100%;object-fit:cover;border-radius:10px">';
    }
  }
  var p = A.getSelectedMulti();
  var pCard = $('select-premium');
  if (p && p.Name) {
    if (pCard) pCard.style.display = 'flex';
    setText('premium-title', p.Name || 'Selecionar servidor');
    setText('premium-sub', p.Info || 'Premium');
    var pwrap = $('premium-flag-wrap');
    if (pwrap && (p.FlagUrl || p.Flag)) {
      var psrc = p.FlagUrl ? p.FlagUrl : 'file:///android_asset/flags/' + p.Flag + '.png';
      pwrap.innerHTML = '<img src="' + esc(psrc) + '" onerror="this.parentElement.innerHTML=\'💎\'" style="width:100%;height:100%;object-fit:cover;border-radius:10px">';
    }
  } else { if (pCard) pCard.style.display = 'none'; }
}

function buildServerList(type) {
  var root = $('list-servers'); if (!root) return;
  root.innerHTML = '';
  var isPremium = (type === 'premium');
  var servers  = isPremium ? A.getMultiServers() : A.getServers();
  var selected = isPremium ? A.getSelectedMulti() : A.getSelected();
  var selPos   = selected ? selected.position : -1;
  if (!servers || !servers.length) {
    root.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:8px">Nenhuma opção disponível no momento.</div>';
    return;
  }
  var mTitleEl = document.querySelector('#modal-servers .modal-title');
  if (mTitleEl) mTitleEl.textContent = isPremium ? 'Servidores Premium' : 'Operadoras';
  servers.forEach(function (s, i) {
    var isSel   = (s.position === selPos || i === selPos);
    var flagSrc = s.FlagUrl ? s.FlagUrl : (s.Flag ? 'file:///android_asset/flags/' + s.Flag + '.png' : '');
    var el = document.createElement('div');
    el.className = 'list-item' + (isSel ? ' selected' : '');
    el.innerHTML = '<div class="li-icon">' + (flagSrc ? '<img src="' + esc(flagSrc) + '" onerror="this.parentElement.innerHTML=\'' + (isPremium ? '💎' : '🌐') + '\'">' : (isPremium ? '💎' : '🌐')) + '</div>' +
      '<div class="li-main"><div class="li-title">' + esc(s.Name || 'Servidor') + '</div><div class="li-sub">' + esc(s.Info || (isPremium ? 'Premium' : 'Direct')) + '</div></div>' +
      '<span class="li-check">✓</span>';
    el.onclick = function () {
      if (app.connected) { toast('Desconecte-se antes de trocar a seleção.', 'err'); return; }
      isPremium ? A.selectMultiServer(s.position !== undefined ? s.position : i) : A.selectServer(s.position !== undefined ? s.position : i);
      closeModal();
      setTimeout(function () { refreshSelected(); }, 250);
      toast(isPremium ? 'Servidor selecionado!' : 'Operadora selecionada!', 'ok');
    };
    root.appendChild(el);
  });
}

function buildServerListPage() {
  var root = $('list-servers-page'); if (!root) return;
  root.innerHTML = '';
  var servers  = A.getServers();
  var selected = A.getSelected();
  var selPos   = selected ? selected.position : -1;
  if (!servers || !servers.length) {
    root.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:18px">Nenhuma opção disponível no momento.</div>';
    return;
  }
  servers.forEach(function (s, i) {
    var isSel   = (s.position === selPos || i === selPos);
    var flagSrc = s.FlagUrl ? s.FlagUrl : (s.Flag ? 'file:///android_asset/flags/' + s.Flag + '.png' : '');
    var el = document.createElement('div');
    el.className = 'list-item' + (isSel ? ' selected' : '');
    el.innerHTML = '<div class="li-icon">' + (flagSrc ? '<img src="' + esc(flagSrc) + '" onerror="this.parentElement.innerHTML=\'🌐\'">' : '🌐') + '</div>' +
      '<div class="li-main"><div class="li-title">' + esc(s.Name || 'Servidor') + '</div><div class="li-sub">' + esc(s.Info || 'Direct') + '</div></div>' +
      '<span class="li-check">✓</span>';
    el.onclick = function () {
      if (app.connected) { toast('Desconecte antes de trocar a seleção.', 'err'); return; }
      A.selectServer(s.position !== undefined ? s.position : i);
      setTimeout(function () { refreshSelected(); buildServerListPage(); }, 250);
      toast('Operadora selecionada!', 'ok');
    };
    root.appendChild(el);
  });
}

function openModal(id) {
  $('modal-mask').classList.add('show');
  document.querySelectorAll('.modal-box').forEach(function (b) { b.classList.remove('active'); });
  var box = $(id); if (box) box.classList.add('active');
}
function closeModal() {
  $('modal-mask').classList.remove('show');
  document.querySelectorAll('.modal-box').forEach(function (b) { b.classList.remove('active'); });
}
function openCredsModal() { loadSavedCredentials(); openModal('modal-creds'); }

/* Tempo restante */
var MAX_FREE_MS = 999999999, timeCard = null, timeFillEl = null, timeValEl = null, timeHandle = null, baseTimeMs = 0;
function initTimeCard() {
  timeCard   = $('time-card');
  timeFillEl = $('time-bar-fill');
  timeValEl  = $('time-remaining-val');
  var adsOn = A.isAdsEnabled();
  var left  = A.getTimeLeft();
  if (!adsOn || left >= MAX_FREE_MS) { if (timeCard) timeCard.classList.remove('show'); return; }
  if (timeCard) timeCard.classList.add('show');
  baseTimeMs = 7200000;
  updateTimeDisplay(left); startTimeCountdown(left);
}
function startTimeCountdown(ms) {
  if (timeHandle) clearInterval(timeHandle);
  var remaining = ms;
  timeHandle = setInterval(function () {
    remaining -= 1000;
    if (remaining <= 0) {
      remaining = 0; clearInterval(timeHandle);
      if (app.connected) A.connect();
      updateTimeDisplay(0);
      toast('Seu tempo expirou! Assista a um anúncio para continuar.', 'warn');
    }
    updateTimeDisplay(remaining);
  }, 1000);
}
function updateTimeDisplay(ms) {
  if (!timeValEl) return;
  if (ms <= 0) { timeValEl.textContent = '00:00'; if (timeFillEl) timeFillEl.style.width = '0%'; return; }
  var totalSec = Math.floor(ms / 1000), h = Math.floor(totalSec / 3600), m = Math.floor((totalSec % 3600) / 60), s = totalSec % 60;
  timeValEl.textContent = (h ? pad(h) + ':' : '') + pad(m) + ':' + pad(s);
  if (timeFillEl) {
    var pct = Math.min(100, (ms / baseTimeMs) * 100);
    timeFillEl.style.width = pct + '%';
    timeFillEl.style.background = pct < 20 ? 'linear-gradient(90deg,#e74c3c,#e67e22)' : 'linear-gradient(90deg,#f0c040,#e67e22)';
  }
}

/* Callbacks do Android */
window.onVpnStatus       = function (raw, detail) { applyState(raw, detail || ''); };
window.onShowInterstitial= function () { A.requestInterstitial(); };
window.onCheckUserReceived = function (data) {
  var card = $('checkuser-card'); if (!card) return;
  card.classList.add('show');
  var u = typeof data === 'string' ? JSON.parse(data) : data;
  setText('cu-username',    u.username || '—');
  setText('cu-connections', (u.count_connection || '—') + ' / ' + (u.limiter_user || '—'));
  setText('cu-expiration',  u.expiration_date || '—');
  setText('cu-days',        (u.expiration_days || '—') + ' dias');
};
window.onLogAdded = function (itemJson) {
  var container = $('log-container'); if (!container) return;
  try {
    var item  = typeof itemJson === 'string' ? JSON.parse(itemJson) : itemJson;
    var level = String(item.level || 'INFO').toUpperCase();
    var time  = item.time ? formatLogTime(item.time) : '';
    var div   = document.createElement('div');
    div.className = 'log-entry ' + level;
    div.innerHTML = '<span class="log-time">' + esc(time) + '</span><span class="log-msg">' + esc(item.message || '') + '</span>';
    container.insertBefore(div, container.firstChild);
  } catch (e) {}
};
window.onLogsCleared  = function () { var c = $('log-container'); if (c) c.innerHTML = ''; };
window.onServerChanged= function () { refreshSelected(); var pg = $('page-servers'); if (pg && pg.classList.contains('active')) buildServerListPage(); };
window.onConfigUpdated= function () { refreshInfo(); refreshSelected(); toast('Configuração atualizada!', 'ok'); };
window.onAdLoading    = function () { var btn = $('btn-watch-ad'); if (btn) { btn.textContent = '⏳ Carregando anúncio...'; btn.disabled = true; } };
window.onTimeAdded    = function (newTotalMs) {
  if (timeHandle) clearInterval(timeHandle);
  updateTimeDisplay(newTotalMs); startTimeCountdown(newTotalMs);
  baseTimeMs = Math.max(baseTimeMs, 7200000);
  var btn = $('btn-watch-ad'); if (btn) { btn.textContent = '📺 Assistir anúncio e ganhar +2 horas'; btn.disabled = false; }
  toast('+2 horas adicionadas!', 'ok');
};
window.onAdFailed = function () {
  var btn = $('btn-watch-ad'); if (btn) { btn.textContent = '📺 Assistir anúncio e ganhar +2 horas'; btn.disabled = false; }
  toast('Falha ao carregar anúncio. Tente novamente.', 'err');
};

/* Método */
var currentMethod = 'SSH';
function selectMethod(m) {
  currentMethod = m;
  setText('method-pill-label', m);
  ['SSH','XRAY','V2RAY'].forEach(function (key) {
    var el = $('method-' + key.toLowerCase());
    if (el) el.classList.toggle('active-method', key === m);
  });
  if (window.Android && typeof Android.setMethod === 'function') Android.setMethod(m);
  closeModal();
  toast('Método: ' + m, 'ok');
}

function toggleCiPass(id) {
  var f = $(id); if (!f) return;
  f.type = f.type === 'password' ? 'text' : 'password';
}

function bind() {
  $('btn-connect').onclick = function () {
    var raw = app.rawState; if (raw === 'PARANDO') return;
    A.connect();
    if (raw === 'CONECTADO') applyState('PARANDO', 'Encerrando túnel...');
    else if (['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO'].indexOf(raw) < 0)
      applyState('INICIANDO', 'Preparando conexão...');
  };

  $('btn-open-method').onclick = function () {
    ['SSH','XRAY','V2RAY'].forEach(function (key) {
      var el = $('method-' + key.toLowerCase());
      if (el) el.classList.toggle('active-method', key === currentMethod);
    });
    openModal('modal-method');
  };

  $('select-server').onclick   = function () { buildServerList('normal');  openModal('modal-servers'); };
  var pCard = $('select-premium');
  if (pCard) pCard.onclick     = function () { buildServerList('premium'); openModal('modal-servers'); };
  $('creds-btn').onclick       = function () { openCredsModal(); };

  $('btn-creds-save').onclick = function () {
    var u   = $('ci-ssh-user').value   || '';
    var p   = $('ci-ssh-pass').value   || '';
    var udp = $('ci-udp-token').value  || '';
    var v2  = $('ci-v2ray-uuid').value || '';
    if (window.Android && typeof window.Android.saveCredentials === 'function') {
      window.Android.saveCredentials(u, p, udp, v2);
      closeModal();
      toast('Credenciais salvas!', 'ok');
    } else {
      toast('Erro: Interface não encontrada', 'err');
    }
  };

  $('btn-update-bottom').onclick = function () { toast('Verificando atualização...', ''); A.checkUpdate(); };
  $('btn-creds-bottom').onclick  = function () { openCredsModal(); };
  $('btn-logs-bottom').onclick   = function () { renderLogs(); openModal('modal-logs'); };

  $('tool-update').onclick  = function () { toast('Verificando atualização...', ''); A.checkUpdate(); };
  $('tool-servers').onclick = function () { buildServerList('normal'); openModal('modal-servers'); };
  $('tool-creds').onclick   = function () { openCredsModal(); };
  $('tool-logs').onclick    = function () { renderLogs(); openModal('modal-logs'); };

  $('btn-refresh-logs').onclick = function () { renderLogs(); };
  $('btn-clear-logs').onclick   = function () {
    A.clearLogs();
    var c = $('log-container'); if (c) c.innerHTML = '<div style="color:var(--muted);font-size:12px;padding:8px">Log limpo.</div>';
    toast('Log limpo.', '');
  };

  document.querySelectorAll('.modal-close').forEach(function (b) { b.onclick = closeModal; });
  $('modal-mask').onclick = function (e) { if (e.target === $('modal-mask')) closeModal(); };

  var btnAd = $('btn-watch-ad');
  if (btnAd) btnAd.onclick = function () { btnAd.textContent = '⏳ Carregando...'; btnAd.disabled = true; A.watchAd(); };
}

function boot() {
  bind();
  initTimeCard();
  refreshInfo();
  refreshSelected();
  applyState(A.getStatus());
  startPolling();
  setInterval(refreshInfo, 15000);
}

if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
else boot();

})();
</script>
